            ContentJson = """{"appRoute":"/oee","startButtonLabel":"Tour OEE","steps":[{"element":"app-date-range-picker","popover":{"title":"Reporting Period","description":"Choose the window OEE is computed over. Quick presets cover Last 30 Days, This Month, and This Week, or pick a custom From/To range. Every work-center card and the detail panel recompute against this period.","side":"bottom"}},{"element":"app-kpi-chip","popover":{"title":"Average OEE & World-Class Count","description":"The toolbar KPIs summarize the whole shop: the average OEE across all work centers (color-coded — green at 85%+, primary at 60-84%, warn below 60%) and how many centers hit the world-class benchmark out of the total.","side":"bottom"}},{"element":".oee-page","popover":{"title":"Work-Center Grid","description":"This area holds one card per work center, each showing the OEE gauge, the three factors (Availability, Performance, Quality), and production counts (total, good, scrap). A star badge marks world-class centers, and you click a card to drill into its detail. When no work center has data in the period, an empty state shows here instead.","side":"top"}},{"element":".oee-page","popover":{"title":"Work-Center Card","description":"Each card in this grid leads with the big OEE number — the product of the three factors below it. Because the factors multiply, OEE is always lower than the weakest factor, so a card tells you at a glance which lever (uptime, speed, or scrap) is holding that center back.","side":"top"}},{"element":".oee-page","popover":{"title":"Detail Panel","description":"Selecting a card opens a detail panel inside this area for that work center, titled with its name. The granularity selector there switches the trend between Daily, Weekly, and Monthly views without changing the reporting period.","side":"top"}},{"element":".oee-page","popover":{"title":"OEE Trend","description":"The detail panel's trend chart plots Availability, Performance, Quality, and the combined OEE over time for the selected work center. Use it to confirm whether an improvement actually moved the number, and to spot which factor is volatile.","side":"top"}},{"element":".oee-page","popover":{"title":"Six Big Losses","description":"The detail panel also breaks the lost minutes into the six classic categories: Equipment Failure and Setup & Adjustment (Availability), Idling and Reduced Speed (Performance), and Process Defects and Reduced Yield (Quality). The dominant category is where to focus improvement effort.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "OEE Field Reference",
            Slug = "oee-field-reference",
            Summary = "Complete reference for the OEE factors and formula, every metric on a work-center calculation, the Six Big Losses, world-class benchmarks, and the dashboard controls.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/oee"]""",
            Tags = """["oee","manufacturing","metrics","reference"]""",
            ContentJson = """{"title":"OEE Field Reference","groups":[{"heading":"The OEE Formula","items":[{"label":"OEE","value":"Availability x Performance x Quality. Always lower than its weakest factor because the three are multiplied. Shown as oeePercent (a percentage) on each card."},{"label":"Availability","value":"Run Time Minutes / Available Minutes. Did the machine run when scheduled? Hurt by breakdowns, unplanned downtime, and long setups."},{"label":"Performance","value":"(Ideal Cycle Time x Total Quantity) / Run Time. Did it run at the ideal speed while running? Hurt by small stops, idling, and reduced speed. Cannot legitimately exceed 100%."},{"label":"Quality","value":"Good Quantity / Total Quantity. How many parts were good? Hurt by scrap and rework."}]},{"heading":"Time Metrics (per work-center calculation)","items":[{"label":"Scheduled Minutes","value":"Total minutes the work center was scheduled to be available in the period."},{"label":"Planned Downtime Minutes","value":"Scheduled stops — breaks, planned maintenance. Subtracted from scheduled time to get available time."},{"label":"Unplanned Downtime Minutes","value":"Unscheduled stops — breakdowns, failures. Costs Availability."},{"label":"Available Minutes","value":"Scheduled minus planned downtime. The denominator for Availability."},{"label":"Run Time Minutes","value":"Minutes the machine was actually running. The numerator for Availability and the denominator for Performance."},{"label":"Ideal Cycle Time (seconds)","value":"The theoretical fastest time to produce one part. Drives the Performance calculation."}]},{"heading":"Production Counts (per work-center calculation)","items":[{"label":"Total Quantity","value":"All parts produced in the period (good + scrap + rework). The denominator for Quality."},{"label":"Good Quantity","value":"Parts that passed first time. The numerator for Quality."},{"label":"Scrap Quantity","value":"Parts discarded as defective. Reduces Quality."},{"label":"Rework Quantity","value":"Parts that had to be reworked — counted against first-time Quality."}]},{"heading":"The Six Big Losses","items":[{"label":"Equipment Failure (Availability)","value":"Lost minutes from breakdowns and unplanned stops. Field: equipmentFailureMinutes."},{"label":"Setup & Adjustment (Availability)","value":"Lost minutes from changeovers, tooling changes, and warm-up. Field: setupAdjustmentMinutes."},{"label":"Idling & Minor Stops (Performance)","value":"Lost minutes from short stoppages, jams, blocked/starved conditions. Field: idlingMinutes."},{"label":"Reduced Speed (Performance)","value":"Lost minutes from running slower than the ideal cycle time. Field: reducedSpeedMinutes."},{"label":"Process Defects (Quality)","value":"Lost minutes from scrap and defects during steady-state running. Field: processDefectsMinutes."},{"label":"Reduced Yield (Quality)","value":"Lost minutes from defects during startup, warm-up, or after a changeover. Field: reducedYieldMinutes."},{"label":"Total Loss Minutes","value":"The sum of all six categories. Field: totalLossMinutes."}]},{"heading":"World-Class Benchmark","items":[{"label":"World-Class OEE","value":"~85% OEE overall (roughly 90% Availability x 95% Performance x 99% Quality). A work center at or above this is flagged isWorldClass and gets a star badge."},{"label":"Average OEE coloring","value":"Toolbar KPI color: green/success at 85% or above, primary at 60-84%, warn below 60%."},{"label":"World-Class Count","value":"Toolbar KPI showing how many work centers are world-class out of the total."}]},{"heading":"Dashboard Controls","items":[{"label":"Period (date range)","value":"Sets the window OEE is computed over. Presets: Last 30 Days, This Month, This Week. Defaults to the last 30 days. Recomputes all cards and the detail panel."},{"label":"Work-Center Grid","value":"One card per work center: OEE gauge, the three factors, and counts (total, good, scrap). Star badge = world-class. Click a card to open its detail."},{"label":"Detail Panel","value":"Opens for the selected work center. Titled with the work-center name. Contains the granularity selector, the trend chart, and the Six Big Losses chart."},{"label":"Granularity","value":"Switches the trend chart between Daily, Weekly, and Monthly. Does not change the reporting period."},{"label":"OEE Trend chart","value":"Plots Availability, Performance, Quality, and combined OEE over time for the selected work center."},{"label":"Six Big Losses chart","value":"Breaks lost minutes into the six categories so you can see which loss dominates."},{"label":"Empty state","value":"When no work centers have data in the period, a 'no work centers' empty state is shown instead of the grid."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "OEE Knowledge Check",
            Slug = "oee-quiz",
            Summary = "Test your knowledge of OEE: the three factors and formula, world-class benchmarks, the Six Big Losses, the metrics behind each factor, and the dashboard.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/oee"]""",
            Tags = """["oee","manufacturing","metrics","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"oe1","text":"What is the OEE formula?","options":[{"id":"a","text":"Availability + Performance + Quality"},{"id":"b","text":"Availability x Performance x Quality","isCorrect":true},{"id":"c","text":"(Availability + Performance + Quality) / 3"},{"id":"d","text":"Run Time / Scheduled Time"}],"explanation":"OEE is the product of the three factors: Availability x Performance x Quality. Because they multiply, OEE is always lower than the weakest factor — losses compound rather than average out."},{"id":"oe2","text":"A work center is 90% Availability, 90% Performance, and 90% Quality. What is its OEE?","options":[{"id":"a","text":"90%"},{"id":"b","text":"about 73%","isCorrect":true},{"id":"c","text":"270%"},{"id":"d","text":"about 95%"}],"explanation":"0.90 x 0.90 x 0.90 = 0.729, or about 73%. This is the key insight of OEE: three 'good-looking' factors still multiply down to a mediocre overall score."},{"id":"oe3","text":"Which factor does an unplanned machine breakdown hurt?","options":[{"id":"a","text":"Quality"},{"id":"b","text":"Performance"},{"id":"c","text":"Availability","isCorrect":true},{"id":"d","text":"None — breakdowns are excluded from OEE"}],"explanation":"Availability is run time divided by available time. A breakdown stops the machine when it should be running, so it directly reduces Availability. (It maps to the Equipment Failure loss category.)"},{"id":"oe4","text":"How is Quality calculated?","options":[{"id":"a","text":"Run Time / Scheduled Time"},{"id":"b","text":"Good Quantity / Total Quantity","isCorrect":true},{"id":"c","text":"Ideal Cycle Time x Total Quantity"},{"id":"d","text":"Scrap Quantity / Good Quantity"}],"explanation":"Quality is good parts divided by total parts produced. Both scrap and rework reduce it — a part that needs rework was not made right the first time, so it counts against first-time quality."},{"id":"oe5","text":"A work center is flagged 'world-class.' What benchmark does that correspond to?","options":[{"id":"a","text":"100% OEE"},{"id":"b","text":"Roughly 85% OEE (about 90% Availability, 95% Performance, 99% Quality)","isCorrect":true},{"id":"c","text":"Exactly 60% OEE"},{"id":"d","text":"Any OEE above 50%"}],"explanation":"The recognized world-class benchmark is about 85% OEE, which breaks down to roughly 90% Availability, 95% Performance, and 99% Quality. Work centers at or above it get the isWorldClass flag and a star badge, and the dashboard counts them."},{"id":"oe6","text":"Reduced Speed (running slower than the ideal cycle time) belongs to which of the Six Big Losses groupings?","options":[{"id":"a","text":"An Availability loss"},{"id":"b","text":"A Performance loss","isCorrect":true},{"id":"c","text":"A Quality loss"},{"id":"d","text":"It is not one of the Six Big Losses"}],"explanation":"Reduced Speed is a Performance loss, alongside Idling & Minor Stops. Availability losses are Equipment Failure and Setup & Adjustment; Quality losses are Process Defects and Reduced Yield."},{"id":"oe7","text":"Which two losses are the Quality-related Six Big Losses?","options":[{"id":"a","text":"Equipment Failure and Setup & Adjustment"},{"id":"b","text":"Idling & Minor Stops and Reduced Speed"},{"id":"c","text":"Process Defects and Reduced Yield","isCorrect":true},{"id":"d","text":"Equipment Failure and Reduced Speed"}],"explanation":"Process Defects (scrap during steady-state running) and Reduced Yield (defects during startup/warm-up or after a changeover) are the two Quality losses. Together with the Availability and Performance pairs, they make up the Six Big Losses that sum to total lost minutes."},{"id":"oe8","text":"What does Available Minutes equal?","options":[{"id":"a","text":"Scheduled Minutes plus planned downtime"},{"id":"b","text":"Scheduled Minutes minus planned downtime","isCorrect":true},{"id":"c","text":"Run Time minus scrap time"},{"id":"d","text":"Total Quantity x Ideal Cycle Time"}],"explanation":"Available time is the scheduled time minus planned downtime (breaks, planned maintenance). It is the denominator for Availability — run time divided by available minutes."},{"id":"oe9","text":"You select a work-center card. What does the detail panel show?","options":[{"id":"a","text":"A list of customers for that work center"},{"id":"b","text":"An OEE trend chart (Availability, Performance, Quality, OEE over time) and a Six Big Losses breakdown","isCorrect":true},{"id":"c","text":"Only the raw scheduled-minutes number"},{"id":"d","text":"An editable form to change the OEE score"}],"explanation":"Selecting a card opens the detail panel for that work center, with a granularity-switchable OEE trend chart and the Six Big Losses chart. OEE is read-only analysis — you can't edit the score; you change it by improving the underlying production."},{"id":"oe10","text":"The OEE page recomputes when you change one particular control. Which is it (and which only affects the trend chart)?","options":[{"id":"a","text":"The period date range recomputes everything; the granularity only changes the trend chart's bucketing","isCorrect":true},{"id":"b","text":"The granularity recomputes everything; the period only affects the trend"},{"id":"c","text":"Neither control affects the data"},{"id":"d","text":"Both controls only affect the KPIs"}],"explanation":"The period (date range) sets the window all cards and the detail panel are computed over. The granularity selector (Daily/Weekly/Monthly) only changes how the trend chart buckets time — it does not change the reporting period."},{"id":"oe11","text":"Why can Performance never legitimately exceed 100%?","options":[{"id":"a","text":"Because the software caps it artificially"},{"id":"b","text":"Because nothing can run faster than the ideal cycle time, which is defined as the theoretical fastest — if Performance exceeds 100%, the ideal cycle time is set too slow","isCorrect":true},{"id":"c","text":"Because Performance is the same as Quality"},{"id":"d","text":"It can — Performance above 100% is normal"}],"explanation":"Performance compares ideal-cycle-time-times-quantity against actual run time. The ideal cycle time is the theoretical fastest achievable, so a value over 100% means the ideal was set too slow, not that the machine beat physics — it's a data-quality signal."},{"id":"oe12","text":"A work center has high Availability and high Performance but low OEE. Where is the problem?","options":[{"id":"a","text":"Quality — scrap and rework are dragging the score down","isCorrect":true},{"id":"b","text":"Availability — the machine isn't running"},{"id":"c","text":"Performance — the machine is running slow"},{"id":"d","text":"There is no problem; OEE is unrelated to the factors"}],"explanation":"Since OEE is the product of the three factors, if Availability and Performance are both high but OEE is low, Quality must be the weak factor — meaning scrap and rework. The Six Big Losses Quality categories (Process Defects, Reduced Yield) would show where."}]}"""
        });

        Log.Information("Seeded OEE training modules");
    }
}
